import { writeOutput } from "./codegen";

const DOCS_URL = "https://scrapeninja.net/docs/getting-started/";
const PLACEHOLDER_VALUE =
  "vm0placeholderScrapeninjaToken0000000000000000000000a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from ScrapeNinja API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:scrapeninja",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const scrapeninjaFirewall: FirewallConfig = {",
    '  name: "scrapeninja",',
    '  description: "ScrapeNinja Web Scraping API",',
    "  placeholders: {",
    `    SCRAPENINJA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://scrapeninja.p.rapidapi.com",',
    "      auth: {",
    "        headers: {",
    '          "X-RapidAPI-Key": "${{ secrets.SCRAPENINJA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "};",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating ScrapeNinja firewall config...");
  const ts = generateTypeScript();
  writeOutput("scrapeninja", ts, import.meta.dirname);
}
